package com.hospital.management.controller.schedule;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.DoctorScheduleServiceImpl;import com.hospital.management.util.RequestUtil;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/schedules/create")public class DoctorScheduleCreateServlet extends HttpServlet{private final DoctorScheduleService service;public DoctorScheduleCreateServlet(){this(new DoctorScheduleServiceImpl());}public DoctorScheduleCreateServlet(DoctorScheduleService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{DoctorScheduleForm f=new DoctorScheduleForm();f.setAvailable(true);show(q,r,f,"CREATE");}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{DoctorScheduleForm f=ScheduleRequest.form(q,null);ServiceResult<Long>x=service.createSchedule(f,RequestUtil.buildAuditContext(q),ScheduleRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/schedules?message=created");return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f,"CREATE");}private void show(HttpServletRequest q,HttpServletResponse r,DoctorScheduleForm f,String mode)throws ServletException,IOException{AuthenticatedUser u=ScheduleRequest.user(q);q.setAttribute("formMode",mode);q.setAttribute("scheduleForm",f);q.setAttribute("doctors",service.getActiveDoctors());if("DOCTOR".equals(u.getRoleName()))q.setAttribute("ownDoctor",service.getOwnDoctor(u).orElse(null));q.getRequestDispatcher("/WEB-INF/views/schedules/form.jsp").forward(q,r);}}
